import { Roles } from '@/types/api.types';

// Returns true when the user is allowed by `requiredRole`. SuperAdmin always passes.
// `requiredRole` can be a single role, an array (any-of), or undefined (no requirement).
export const hasRequiredRole = (
  requiredRole: Roles | Roles[] | undefined,
  userRoles: Roles[],
): boolean => {
  if (!requiredRole) return true;
  if (userRoles.includes(Roles.SuperAdmin)) return true;
  const required = Array.isArray(requiredRole) ? requiredRole : [requiredRole];
  return required.some(r => userRoles.includes(r));
};
